// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	var taskTable = "x_153465_discovert_route_task_instance";
	var scriptLogTag = "(Business Rule) Task - Mark Completed / Inactive: ";

	var fRecurseUpdate = function(active, task) {
		task.setValue("active", active);
		// STRY0106180 - clear all request fields
		task.u_clarification_requested = false;
		task.extension_requested = false;
		task.reassignment_requested = false;
		task.extended_suspense_date = null;
		var task_state = parseInt(task.getValue('state'));
		task.update();

		// STRY0106180 - Find all open requests for the task and close them.
		var requests = new GlideRecord('x_153465_discovert_tasker_requests');
		requests.addQuery('u_status', 'In progress');
		requests.addQuery('parent', task.sys_id);
		requests.query();
		while(requests.next()) {
			requests.setValue("u_status", 'Completed');
			switch (task_state) {
				// Task was cancelled
				case 7:
					requests.setValue("u_response_comments", gs.getMessage('Tasker - Open Request Comment for cancelled task'));
					break;
				// Task was completed
				case 3: case 4:
					requests.setValue("u_response_comments", gs.getMessage('Tasker - Open Request Comment for Closed tasks'));
					break;
			}
			requests.update();
		}
		// 2.7.0 | 2021-09-22 | mmcc | STRY0108861 - DIA- Cancel from Top Task Notification 
//		// find all tasks where this task is parent task and
// 		var children = new GlideRecord(taskTable);
// 		children.addQuery("parent", task.sys_id);
// 		//children.addEncodedQuery('tasker_type!=f6b066b11b1b00104f5221b5ec4bcb92');//KT ACK: STRY0053207
// 		//children.addEncodedQuery('tasker_type!=b0e0aa711b1b00104f5221b5ec4bcb3d');//KT ITT: STRY0053216
// 		children.query();
// 		while(children.next()) {
// 			children.setValue("active", active);
// 			children.update();
// 		}
	};
	try {
		var active = current.getValue("active");
		fRecurseUpdate(active, current);
	} catch(outerException) {
		gs.warn(scriptLogTag + outerException);
	}

})(current, previous);
